import { subscribe } from '../../rules/index.js';

export default function decorate(fieldDiv, fieldJson, container, formId) {
  // fieldDiv contains the base checkbox-group HTML structure
  // checkbox-group has:
  // - <fieldset class="checkbox-group-wrapper">
  // - <legend class="field-label">Group Label</legend>
  // - <div class="checkbox-wrapper"> for each option
  //   - <input type="checkbox" id="{fieldId}" name="{name}" value="{value}">
  //   - <label for="{fieldId}" class="field-label">{Option Label}</label>
  // - <div class="field-description">

  let model = null;

  subscribe(fieldDiv, formId, (_fieldDiv, fieldModel, eventType, payload) => {
    if (eventType === 'register') {
      model = fieldModel;
      // One-time setup: transform checkbox wrappers into chip elements
      transformCheckboxesToChips(fieldDiv, fieldModel);
    } else if (eventType === 'change') {
      payload?.changes?.forEach((change) => {
        if (change?.propertyName === 'value') {
          // Sync chip visual state when value changes
          updateChipStates(fieldDiv, model);
        } else if (change?.propertyName === 'enum' || change?.propertyName === 'enumNames') {
          // Re-render chips if options change
          clearChips(fieldDiv);
          transformCheckboxesToChips(fieldDiv, fieldModel);
        }
      });
    }
  }, { listenChanges: true });

  return fieldDiv;
}

/**
 * Transform checkbox wrappers into chip elements
 */
function transformCheckboxesToChips(fieldDiv, fieldModel) {
  const checkboxWrappers = fieldDiv.querySelectorAll('.checkbox-wrapper');

  checkboxWrappers.forEach((wrapper) => {
    const checkbox = wrapper.querySelector('input[type="checkbox"]');
    const label = wrapper.querySelector('label');

    if (!checkbox || !label) return;

    // Transform wrapper into a chip button
    wrapper.classList.add('chip-item');
    wrapper.setAttribute('role', 'button');
    wrapper.setAttribute('tabindex', '0');

    // Extract the label text
    const labelText = label.textContent;

    // Hide the checkbox and label (they're still there for accessibility)
    checkbox.classList.add('chip-input-hidden');
    label.classList.add('chip-label-hidden');

    // Create a visual chip element
    const chipButton = document.createElement('div');
    chipButton.className = 'chip-button';
    chipButton.textContent = labelText;

    // If checkbox is checked, add active state
    if (checkbox.checked) {
      chipButton.classList.add('chip-active');
    }

    // Insert chip button before the checkbox
    wrapper.insertBefore(chipButton, checkbox);

    // Handle chip click to toggle checkbox
    chipButton.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      checkbox.checked = !checkbox.checked;
      // Dispatch change event on the underlying input
      checkbox.dispatchEvent(new Event('change', { bubbles: true }));
    });

    // Handle keyboard activation (Enter/Space)
    wrapper.addEventListener('keydown', (e) => {
      if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        checkbox.checked = !checkbox.checked;
        checkbox.dispatchEvent(new Event('change', { bubbles: true }));
      }
    });

    // Keep checkbox hidden but functional for form submission
    checkbox.addEventListener('change', (e) => {
      const chipBtn = wrapper.querySelector('.chip-button');
      if (chipBtn) {
        if (checkbox.checked) {
          chipBtn.classList.add('chip-active');
        } else {
          chipBtn.classList.remove('chip-active');
        }
      }
    });
  });
}

/**
 * Update chip visual states based on model value
 */
function updateChipStates(fieldDiv, fieldModel) {
  const checkboxWrappers = fieldDiv.querySelectorAll('.checkbox-wrapper');
  const selectedValues = fieldModel.value || [];

  checkboxWrappers.forEach((wrapper) => {
    const checkbox = wrapper.querySelector('input[type="checkbox"]');
    const chipButton = wrapper.querySelector('.chip-button');

    if (checkbox && chipButton) {
      const isChecked = selectedValues.includes(checkbox.value);
      if (isChecked) {
        chipButton.classList.add('chip-active');
      } else {
        chipButton.classList.remove('chip-active');
      }
    }
  });
}

/**
 * Clear existing chips
 */
function clearChips(fieldDiv) {
  const chipButtons = fieldDiv.querySelectorAll('.chip-button');
  chipButtons.forEach((btn) => btn.remove());
}

